  /* ── MODAL NOMBRE DE EQUIPO ── */
  'team_modal.title': {es:'¡EQUIPO COMPLETO!', en:'SQUAD COMPLETE!', pt:'TIME COMPLETO!', fr:'ÉQUIPE COMPLÈTE !', de:'KADER VOLLSTÄNDIG!', it:'SQUADRA COMPLETA!'},
  'team_modal.body': {es:'Tu plantilla GOAT está lista. ¡Dale un nombre a tu equipo antes de empezar el torneo! Empezarás en la <strong>Fase de Grupos</strong>: 3 partidos, los 2 primeros del grupo avanzan a octavos de final.', en:'Your GOAT squad is ready. Give your team a name before starting the tournament! You will start in the <strong>Group Stage</strong>: 3 matches, the top 2 in the group advance to the Round of 16.', pt:'Seu elenco GOAT está pronto. Dê um nome ao seu time antes de começar o torneio! Você começará na <strong>Fase de Grupos</strong>: 3 jogos, os 2 primeiros do grupo avançam para as oitavas.', fr:'Votre effectif GOAT est prêt. Donnez un nom à votre équipe avant de commencer le tournoi ! Vous commencerez en <strong>Phase de groupes</strong> : 3 matchs, les 2 premiers du groupe passent en huitièmes.', de:'Dein GOAT-Kader ist bereit. Gib deinem Team einen Namen, bevor du das Turnier beginnst! Du startest in der <strong>Gruppenphase</strong>: 3 Spiele, die Top 2 der Gruppe kommen ins Achtelfinale.', it:'La tua rosa GOAT è pronta. Dai un nome alla tua squadra prima di iniziare il torneo! Inizierai nella <strong>Fase a gironi</strong>: 3 partite, le prime 2 del girone avanzano agli ottavi di finale.'},
  'team_modal.placeholder': {es:'Ej: Dream Team FC', en:'E.g. Dream Team FC', pt:'Ex: Dream Team FC', fr:'Ex : Dream Team FC', de:'z.B. Dream Team FC', it:'Es: Dream Team FC'},
