  'patch.v351_match': {es:'v0.351 — Partido', en:'v0.351 — Match', pt:'v0.351 — Partida', fr:'v0.351 — Match', de:'v0.351 — Spiel', it:'v0.351 — Partita'},
  'patch.v351_match_1': {es:'Feed de partido en 3 columnas: mi equipo izquierda, minuto centro, rival derecha.', en:'3-column match feed: my team on the left, minute in the centre, opponent on the right.', pt:'Feed de partida em 3 colunas: meu time à esquerda, minuto no centro, rival à direita.', fr:'Feed de match en 3 colonnes : mon équipe à gauche, minute au centre, adversaire à droite.', de:'3-spaltiger Spiel-Feed: mein Team links, Minute mittig, Gegner rechts.', it:'Feed partita a 3 colonne: la mia squadra a sinistra, minuto al centro, rivale a destra.'},
  'patch.v351_match_2': {es:'Lesiones y tarjetas bidireccionales: la falta que causa una lesión genera tarjeta al jugador que la comete.', en:'Two-way injuries and cards: the foul that causes an injury gives a card to the fouling player.', pt:'Lesões e cartões bidirecionais: a falta que causa lesão gera cartão ao jogador que a cometeu.', fr:'Blessures et cartons bidirectionnels : la faute causant une blessure donne un carton au fautif.', de:'Bidirektionale Verletzungen und Karten: das Foul, das eine Verletzung verursacht, gibt dem Verursacher eine Karte.', it:'Infortuni e cartellini bidirezionali: il fallo che causa un infortunio genera un cartellino al giocatore che lo commette.'},
  'patch.v351_match_3': {es:'El rival también puede sufrir lesiones y tarjetas durante el partido.', en:'The opponent can also suffer injuries and cards during the match.', pt:'O rival também pode sofrer lesões e cartões durante a partida.', fr:'L\'adversaire peut aussi subir des blessures et des cartons pendant le match.', de:'Auch der Gegner kann während des Spiels Verletzungen und Karten erleiden.', it:'Anche il rivale può subire infortuni e cartellini durante la partita.'},
  'patch.v351_match_4': {es:'Expulsión con banquillo lleno: el jugador permanece en campo con rating 0.', en:'Sending off with a full bench: the player stays on the pitch with 0 rating.', pt:'Expulsão com banco cheio: o jogador permanece em campo com rating 0.', fr:'Expulsion avec banc plein : le joueur reste sur le terrain avec un rating 0.', de:'Platzverweis bei voller Bank: der Spieler bleibt mit 0 Bewertung auf dem Feld.', it:'Espulsione con panchina piena: il giocatore rimane in campo con rating 0.'},
  'patch.v351_match_5': {es:'Los estados de convocados se actualizan solo al finalizar el partido.', en:'Squad statuses update only when the match ends.', pt:'Os estados dos convocados são atualizados apenas ao finalizar a partida.', fr:'Les statuts de l\'effectif ne sont mis à jour qu\'à la fin du match.', de:'Der Kaderstatus wird nur nach Spielende aktualisiert.', it:'Gli stati dei convocati si aggiornano solo al termine della partita.'},
  'patch.v351_tickets': {es:'v0.351 — Tickets', en:'v0.351 — Tickets', pt:'v0.351 — Tickets', fr:'v0.351 — Tickets', de:'v0.351 — Tickets', it:'v0.351 — Ticket'},
  'patch.v351_tickets_1': {es:'Composicion: 1 X roja, 1 cabra (+4pts), 7 monedas (+1pt). Máximo 11pts por boleto.', en:'Composition: 1 red X, 1 goat (+4pts), 7 coins (+1pt). Maximum 11pts per card.', pt:'Composição: 1 X vermelha, 1 cabra (+4pts), 7 moedas (+1pt). Máximo 11pts por ticket.', fr:'Composition : 1 X rouge, 1 chèvre (+4pts), 7 pièces (+1pt). Maximum 11pts par ticket.', de:'Zusammensetzung: 1 rotes X, 1 Ziege (+4Pkt.), 7 Münzen (+1Pkt.). Maximal 11Pkt. pro Los.', it:'Composizione: 1 X rossa, 1 capra (+4pts), 7 monete (+1pt). Massimo 11pts per ticket.'},
  'patch.v351_tickets_2': {es:'Tickets disponibles a las 0:00, 4:00, 8:00, 12:00, 16:00 y 20:00 hora local.', en:'Tickets available at 00:00, 04:00, 08:00, 12:00, 16:00 and 20:00 local time.', pt:'Tickets disponíveis às 0h, 4h, 8h, 12h, 16h e 20h (hora local).', fr:'Tickets disponibles à 0h, 4h, 8h, 12h, 16h et 20h (heure locale).', de:'Tickets verfügbar um 0:00, 4:00, 8:00, 12:00, 16:00 und 20:00 Ortszeit.', it:'Ticket disponibili alle 0:00, 4:00, 8:00, 12:00, 16:00 e 20:00 ora locale.'},
  'patch.v351_tickets_3': {es:'Sonido al ganar y al perder el boleto.', en:'Sound when winning and losing the card.', pt:'Som ao ganhar e ao perder o ticket.', fr:'Son lors d\'une victoire et d\'une défaite au ticket.', de:'Ton beim Gewinnen und Verlieren des Loses.', it:'Suono quando si vince e si perde il ticket.'},
  'patch.v351_upgrades': {es:'v0.351 — Mejoras y Habilidades', en:'v0.351 — Upgrades & Skills', pt:'v0.351 — Melhorias e Habilidades', fr:'v0.351 — Améliorations et Compétences', de:'v0.351 — Verbesserungen und Fähigkeiten', it:'v0.351 — Miglioramenti e Abilità'},
  'patch.v351_upgrades_1': {es:'Nueva pestaña MEJORAS: banquillo, cambios y convocados mejorables con GOAT Points.', en:'New UPGRADES tab: bench, substitutions and squad upgradeable with GOAT Points.', pt:'Nova aba MELHORIAS: banco, substituições e convocados melhoráveis com GOAT Points.', fr:'Nouvel onglet AMÉLIORATIONS : banc, remplacements et effectif améliorables avec des GOAT Points.', de:'Neuer VERBESSERUNGEN-Tab: Bank, Wechsel und Kader mit GOAT Points verbesserbar.', it:'Nuova scheda MIGLIORAMENTI: panchina, sostituzioni e rosa migliorabili con GOAT Points.'},
  'patch.v351_upgrades_2': {es:'Nueva pestaña HABILIDADES: modificadores especiales comprables con GOAT Points.', en:'New SKILLS tab: special modifiers purchaseable with GOAT Points.', pt:'Nova aba HABILIDADES: modificadores especiais compráveis com GOAT Points.', fr:'Nouvel onglet COMPÉTENCES : modificateurs spéciaux achetables avec des GOAT Points.', de:'Neuer FÄHIGKEITEN-Tab: spezielle Modifikatoren käuflich mit GOAT Points.', it:'Nuova scheda ABILITÀ: modificatori speciali acquistabili con GOAT Points.'},
  'patch.v351_upgrades_3': {es:'Mejora RECUPERACIÓN: reduce la fatiga acumulada por partido.', en:'RECOVERY upgrade: reduces accumulated fatigue per match.', pt:'Melhoria RECUPERAÇÃO: reduz a fadiga acumulada por partida.', fr:'Amélioration RÉCUPÉRATION : réduit la fatigue accumulée par match.', de:'Verbesserung ERHOLUNG: reduziert die pro Spiel angesammelte Ermüdung.', it:'Miglioramento RECUPERO: riduce la fatica accumulata per partita.'},
  'patch.v351_upgrades_4': {es:'Las mejoras tienen efecto real en el juego en tiempo real.', en:'Upgrades have real in-game effects in real time.', pt:'As melhorias têm efeito real no jogo em tempo real.', fr:'Les améliorations ont un effet réel dans le jeu en temps réel.', de:'Die Verbesserungen haben echten Effekt im Spiel in Echtzeit.', it:'I miglioramenti hanno un effetto reale nel gioco in tempo reale.'},
  'patch.v35_base': {es:'v0.35 — Sistema base', en:'v0.35 — Base system', pt:'v0.35 — Sistema base', fr:'v0.35 — Système de base', de:'v0.35 — Grundsystem', it:'v0.35 — Sistema base'},
  'patch.v35_base_1': {es:'Simulación en vivo 0-90+X minutos con descanso, prórroga y penaltis ABAB.', en:'Live simulation 0-90+X minutes with half time, extra time and ABAB penalties.', pt:'Simulação ao vivo 0-90+X minutos com intervalo, prorrogação e pênaltis ABAB.', fr:'Simulation en direct 0-90+X minutes avec mi-temps, prolongation et tirs au but ABAB.', de:'Live-Simulation 0-90+X Minuten mit Halbzeit, Verlängerung und ABAB-Elfmeterschießen.', it:'Simulazione dal vivo 0-90+X minuti con intervallo, supplementari e rigori ABAB.'},
